/* 12-Agent AI Super Coding Brain integration engine */
window.BrainCommandCenter = (function(){
  const commands = [];
  const agents = window.SuperCodingBrain12 || {};

  async function addCommand(commandText){
    const parsed = await agents.SyntaxAgent.parseCommand(commandText);
    const generatedFiles = await agents.CodeAgent.generateFiles(parsed);
    commands.push({id:Date.now(), name:parsed.name, description:parsed.description, files:generatedFiles});
    await integrateCommand(generatedFiles);
    renderDashboard();
  }

  async function editCommand(id){
    const cmd = commands.find(c=>c.id===id);
    if(!cmd) return;
    const updatedText = prompt('Edit Brain Command:', cmd.description);
    if(updatedText){
      const parsed = await agents.SyntaxAgent.parseCommand(updatedText);
      const newFiles = await agents.CodeAgent.generateFiles(parsed);
      cmd.name = parsed.name;
      cmd.description = parsed.description;
      cmd.files = newFiles;
      await integrateCommand(newFiles);
      renderDashboard();
    }
  }

  async function testCommand(id){
    const cmd = commands.find(c=>c.id===id);
    if(!cmd) return;
    const output = await agents.TestingAgent.runSandbox(cmd.files);
    console.log('Test output for command', cmd.name, output);
    alert(JSON.stringify(output,null,2));
  }

  async function removeCommand(id){
    const index = commands.findIndex(c=>c.id===id);
    if(index>=0){
      await agents.DeploymentAgent.removeModule(commands[index].files);
      commands.splice(index,1);
      renderDashboard();
    }
  }

  async function integrateCommand(files){
    await agents.DeploymentAgent.deployFiles(files);
    await agents.UIAgent.updateDashboard();
  }

  function renderDashboard(){
    // refresh UI handled by Figma Make bindings
  }

  return {addCommand, editCommand, testCommand, removeCommand, commands};
})();
